def test_process_data_standard_mode_returns_list():
    data = [1, 2, 3, 4, 5]
    assert len(process_data(data, mode='standard')) == 5

def test_process_data_aggressive_mode_returns_list():
    data = [1, 2, 3, 4, 5]
    assert len(process_data(data, mode='aggressive')) == 5

def test_process_data_invalid_mode_raises_no_error():
    data = [1, 2, 3, 4, 5]
    assert not process_data(data, mode='invalid')

def test_process_data_non_list_data_raises_error():
    with pytest.raises(ValueError, match="Data must be a list"):
        process_data(1, threshold=10)

def test_calculate_risk_non_zero_factor_returns_non_zero():
    assert calculate_risk(50, 1) != 0

def test_calculate_risk_non_integer_factor_returns_non_zero():
    assert calculate_risk(50, 1.5) != 0
```

